#define OPEN
#define ITERATION
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);

static inline void usage(int argc, char **argv)
{
	(void)argc;
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");
	exit(1);
}

#define CUDA_CHECK(call) do { \
	cudaError_t _e = (call); \
	if (_e != cudaSuccess) { \
		fprintf(stderr, "CUDA error %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(_e)); \
		exit(1); \
	} \
} while (0)

__global__ void compute_coeff_kernel(
	const float *J, float *dN, float *dS, float *dW, float *dE, float *c,
	int rows, int cols, float q0sqr)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;
	if (i >= rows || j >= cols) return;

	int k = i * cols + j;
	float Jc = J[k];

	int iN = (i == 0) ? 0 : (i - 1);
	int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
	int jW = (j == 0) ? 0 : (j - 1);
	int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

	dN[k] = J[iN * cols + j] - Jc;
	dS[k] = J[iS * cols + j] - Jc;
	dW[k] = J[i * cols + jW] - Jc;
	dE[k] = J[i * cols + jE] - Jc;

	float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);
	float L  = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

	float num  = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
	float den  = 1.0f + (0.25f * L);
	float qsqr = num / (den * den);

	den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
	float ck = 1.0f / (1.0f + den);

	if (ck < 0.0f) ck = 0.0f;
	else if (ck > 1.0f) ck = 1.0f;
	c[k] = ck;
}

__global__ void update_kernel(
	float *J, const float *c, const float *dN, const float *dS, const float *dW, const float *dE,
	int rows, int cols, float lambda)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;
	if (i >= rows || j >= cols) return;

	int k = i * cols + j;

	int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
	int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

	float cN = c[k];
	float cS = c[iS * cols + j];
	float cW = c[k];
	float cE = c[i * cols + jE];

	float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];
	J[k] = J[k] + 0.25f * lambda * D;
}

int main(int argc, char* argv[])
{
	int rows, cols, size_I, size_R, niter = 10, iter, k;
	float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
	int *iN, *iS, *jE, *jW;
	float *dN, *dS, *dW, *dE;
	int r1, r2, c1, c2;
	float *c;
	float lambda;
	int i, j;
	int nthreads;

	if (argc == 10) {
		rows = atoi(argv[1]);
		cols = atoi(argv[2]);
		if ((rows % 16 != 0) || (cols % 16 != 0)) {
			fprintf(stderr, "rows and cols must be multiples of 16\n");
			exit(1);
		}
		r1 = atoi(argv[3]);
		r2 = atoi(argv[4]);
		c1 = atoi(argv[5]);
		c2 = atoi(argv[6]);
		nthreads = atoi(argv[7]);
		(void)nthreads;
		lambda = (float)atof(argv[8]);
		niter = atoi(argv[9]);
	} else {
		usage(argc, argv);
	}

	size_I = cols * rows;
	size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

	I = (float *)malloc(size_I * sizeof(float));
	J = (float *)malloc(size_I * sizeof(float));
	c = (float *)malloc(sizeof(float) * size_I);

	iN = (int *)malloc(sizeof(unsigned int*) * rows);
	iS = (int *)malloc(sizeof(unsigned int*) * rows);
	jW = (int *)malloc(sizeof(unsigned int*) * cols);
	jE = (int *)malloc(sizeof(unsigned int*) * cols);

	dN = (float *)malloc(sizeof(float) * size_I);
	dS = (float *)malloc(sizeof(float) * size_I);
	dW = (float *)malloc(sizeof(float) * size_I);
	dE = (float *)malloc(sizeof(float) * size_I);

	for (int ii = 0; ii < rows; ii++) {
		iN[ii] = ii - 1;
		iS[ii] = ii + 1;
	}
	for (int jj = 0; jj < cols; jj++) {
		jW[jj] = jj - 1;
		jE[jj] = jj + 1;
	}
	iN[0] = 0;
	iS[rows - 1] = rows - 1;
	jW[0] = 0;
	jE[cols - 1] = cols - 1;

	printf("Randomizing the input matrix\n");

	random_matrix(I, rows, cols);

	for (k = 0; k < size_I; k++) {
		J[k] = (float)exp((double)I[k]);
	}

	float *d_J = NULL, *d_c = NULL, *d_dN = NULL, *d_dS = NULL, *d_dW = NULL, *d_dE = NULL;
	CUDA_CHECK(cudaMalloc((void **)&d_J, size_I * sizeof(float)));
	CUDA_CHECK(cudaMalloc((void **)&d_c, size_I * sizeof(float)));
	CUDA_CHECK(cudaMalloc((void **)&d_dN, size_I * sizeof(float)));
	CUDA_CHECK(cudaMalloc((void **)&d_dS, size_I * sizeof(float)));
	CUDA_CHECK(cudaMalloc((void **)&d_dW, size_I * sizeof(float)));
	CUDA_CHECK(cudaMalloc((void **)&d_dE, size_I * sizeof(float)));

	printf("Start the SRAD main loop\n");

#ifdef ITERATION
	for (iter = 0; iter < niter; iter++) {
#endif
		sum = 0.0f;
		sum2 = 0.0f;
		for (i = r1; i <= r2; i++) {
			for (j = c1; j <= c2; j++) {
				tmp = J[i * cols + j];
				sum += tmp;
				sum2 += tmp * tmp;
			}
		}
		meanROI = sum / (float)size_R;
		varROI = (sum2 / (float)size_R) - meanROI * meanROI;
		q0sqr = varROI / (meanROI * meanROI);

		CUDA_CHECK(cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice));

		dim3 block(BLOCK_SIZE, BLOCK_SIZE);
		dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

		compute_coeff_kernel<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, q0sqr);
		CUDA_CHECK(cudaGetLastError());

		update_kernel<<<grid, block>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE, rows, cols, lambda);
		CUDA_CHECK(cudaGetLastError());

		CUDA_CHECK(cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost));
#ifdef ITERATION
	}
#endif

#ifdef OUTPUT
	for (int ii = 0; ii < rows; ii++) {
		for (int jj = 0; jj < cols; jj++) {
			printf("%.5f ", J[ii * cols + jj]);
		}
		printf("\n");
	}
#endif

	printf("Computation Done\n");

	CUDA_CHECK(cudaFree(d_J));
	CUDA_CHECK(cudaFree(d_c));
	CUDA_CHECK(cudaFree(d_dN));
	CUDA_CHECK(cudaFree(d_dS));
	CUDA_CHECK(cudaFree(d_dW));
	CUDA_CHECK(cudaFree(d_dE));

	free(I);
	free(J);
	free(iN);
	free(iS);
	free(jW);
	free(jE);
	free(dN);
	free(dS);
	free(dW);
	free(dE);
	free(c);

	return 0;
}

